				-1px -1px 0 #20a53a,
				1px -1px 0 #20a53a,
				-1px 1px 0 #20a53a,
				1px 1px 3px rgba(0, 0, 0, 0.5);

			transition: all 0.5s ease;
		}

		.black-friday:hover {
			color: #fc5634 !important;
			text-shadow: none;
		}

		.black-friday-box {
			position: relative;
			width: 1425px;
		}

		.black-box {
			display: none;
			align-items: center;
			justify-content: center;
			height: 50px;
			background: linear-gradient(to right, #e501c6, #3806b4);
			border-radius: 4px 4px 0 0;
			color: white;
			font-size: 18px;
			text-align: center;
			cursor: pointer;
		}

		.black-box .save-text {
			font-weight: bold;
			font-size: 19px;
			padding: 0 30px;
		}

		.black-box .friday-text {
			font-weight: bold;
		}

		.black-box .start-text {
			color: white;
			padding: 8px 15px;
			border-radius: 4px;
			background-color: #e301c6;
			animation: slide-in 1s forwards, glow 1s ease-in-out 1s forwards;
		}

		@keyframes  slide-in {
			0% {
				transform: translateX(100%);
				opacity: 0;
			}

			100% {
				transform: translateX(0);
				opacity: 1;
			}
		}

		@keyframes  glow {

			0%,
			100% {
				box-shadow: none;
			}

			50% {
				box-shadow: 0 0 20px rgba(255, 255, 255, 0.8);
			}
		}

