	<script src="/static/new/js/swiper.min.js" type="text/javascript" charset="utf-8"></script>
<script src="/static/new/js/wave.min.js" type="text/javascript" charset="utf-8"></script>
<script>
	$(function() {
		var wave = new Wave('#waves', {
			colors: ['rgba(255, 255, 255, 1)', 'rgba(255, 255, 255, .6)', 'rgba(255, 255, 255, .4)'],
			smooth: 70,
			velocity: 0.6,
			position: 'bottom',
			height: [70, 80, 90],
		});

		wave.animate();

		// 合作伙伴
		new Swiper('.partners-swiper', {
			slidesPerView: 6,
			spaceBetween: 0,
			loop: true,
			speed: 800,
			navigation: {
				nextEl: '.swiper-button-next',
				prevEl: '.swiper-button-prev',
			},
			breakpoints: {
				768: {
					slidesPerView: 2,
					spaceBetween: 0,
				},
				950: {
					slidesPerView: 3,
					spaceBetween: 0,
				},
				1199: {
					slidesPerView: 5,
					spaceBetween: 0,
				},
			},
		});


		window.addEventListener("scroll", function(e) {
			// 当发生滚动事件时调用ergodic事件
			ergodic();
		});

		function ergodic() {
			var images = document.getElementsByTagName("img");
			// 遍历每一张图
			for (var i of images) {
				// 判断当前图片是否在可视区内
				if (i.getBoundingClientRect().top < window.innerHeight) {
					// 获取自定义data-src属性的值
					var trueSrc = i.getAttribute("data-src");
					var imgSrc = i.getAttribute("src");
					// 把值赋值给图片的src属性
					if (!imgSrc) i.setAttribute("src", trueSrc);
				}
			}
		}

		ergodic();

		let isDragging = false;
		let animationId = null;
		const container = document.getElementById('sliderContainer');
		const afterImg = document.getElementById('afterImg');
		const slider = document.getElementById('slider');

		// 添加鼠标按下时的视觉反馈
		slider.addEventListener('mousedown', (e) => {
			isDragging = true;
			slider.style.transform = 'scale(1.1)';
			e.preventDefault(); // 防止默认行为
		});

		document.addEventListener('mouseup', () => {
			isDragging = false;
			slider.style.transform = 'scale(1)';
			if (animationId) {
				cancelAnimationFrame(animationId);
				animationId = null;
			}
		});

		// 使用requestAnimationFrame优化性能
		document.addEventListener('mousemove', e => {
			if (!isDragging) return;

			if (animationId) {
				cancelAnimationFrame(animationId);
			}

			animationId = requestAnimationFrame(() => {
				const rect = container.getBoundingClientRect();
				// 更精确的边界计算
				const x = Math.max(0, Math.min(e.clientX - rect.left, rect.width));
				const percent = (x / rect.width) * 100;

				// 使用CSS变量和transition实现更平滑的过渡
				afterImg.style.clipPath = `inset(0 ${100 - percent}% 0 0)`;
				slider.style.left = `${percent}%`;
			});
		});

		// 添加触摸支持（移动端）
		slider.addEventListener('touchstart', (e) => {
			isDragging = true;
			slider.style.transform = 'scale(1.1)';
			e.preventDefault();
		});

		document.addEventListener('touchend', () => {
			isDragging = false;
			slider.style.transform = 'scale(1)';
		});

		document.addEventListener('touchmove', (e) => {
			if (!isDragging) return;
			e.preventDefault();

			const touch = e.touches[0];
			const rect = container.getBoundingClientRect();
			const x = Math.max(0, Math.min(touch.clientX - rect.left, rect.width));
			const percent = (x / rect.width) * 100;

			afterImg.style.clipPath = `inset(0 ${100 - percent}% 0 0)`;
			slider.style.left = `${percent}%`;
		});
	});
	// 2s后弹出黑五窗口
	setTimeout(()=>{
		const view_event = localStorage.getItem("isFinish")
		const isOpen = getCookie("isClose")
		console.log(view_event,isOpen)
		if(view_event === 'false' && isOpen !== 'true'){
	layer.open({
		type: 1,
		area: ['600px', '440px'],
		title: false,
		shade: 0.5,
		closeBtn: 2,
		content: '\
		<div class="black_layer">\
			<div class="title_h1">Black Friday</div>\
			<div class="title_h1">And Cyber Monday</div>\
			<div class="divider"></div>\
			<div class="title_h3">\
				<svg width="300" height="100" class="svg">\
					<text x="50%" y="50%" text-anchor="middle" dominant-baseline="middle" font-size="60" class="text">Big Sale!</text>\
				</svg>\
				<div class="title_h2">aaPanel-Pro for only $399/Lifetime</div>\
			</div>\
			<div class="title_h4"><img class="curror" src="data:image/png;base64,"/></div>\
			<div class="button">Get deal</div>\
		</div>',
		end: function() {
			// 存储用户关闭状态
			setCookies({isClose : true},1)
		},
		success: (layers, indexs) => {
			$('.black_layer .button').click(function(){
				setCookies({isClose : true},1)
				layer.close(indexs)
				window.location.href = "/black_friday"
			})
		},
	});
		}
	},2000)
	function getCookie(name) {
		const value = `; ${document.cookie}`;
		const parts = value.split(`; ${name}=`);
		if (parts.length === 2) {
			return parts.pop().split(';').shift(); // 返回 cookie 的值
		}
		return null; // 如果没有找到，返回 null
	}
	// 设置cookie存储
	function setCookies(obj, limitTime) {
		let data = new Date( new Date().getTime() + limitTime*24*60*60*1000 ).toUTCString()
		for(let i in obj) {
			document.cookie = i + '=' + obj[i] + ';expires=' + data
		}
	}

	const invite_code = location.search.match(/\?invite_code=([0-9A-z]*)/)
	if(invite_code) {
		// 会话存储
		sessionStorage.setItem('invite_code', invite_code[1])
	}

	// 顶部aacloud相关事件
	document.addEventListener('DOMContentLoaded', function() {
		// Check localStorage as requested
		if (!localStorage.getItem('aaCloud_bottom') && false) {
			setTimeout(function() {
				var bar = document.getElementById('bottomPromoBar');
				if (bar) bar.style.display = 'flex';
			}, 500);
		}
	});

	function closeBottomPromo() {
		var bar = document.getElementById('bottomPromoBar');
		if (bar) {
			bar.style.transform = 'translateY(100%)';
			setTimeout(function() {
				bar.style.display = 'none';
			}, 300);
			// Record choice in localStorage
			localStorage.setItem('aaCloud_bottom', 'true');
		}
	}
</script>

